{
  "repo": "github.com/sg-evals/firefox--871325b8",
  "summary": "Firefox uses Servo (Rust) as its CSS engine. calc() expression parsing is implemented entirely in Rust. C++ participates via: (1) a thin wrapper that invokes Servo's parser, (2) inline C++ helpers that resolve the Rust-generated calc AST to layout coordinates, and (3) several C++ call-sites that apply overflow/clamping when converting resolved float values to the fixed-width nscoord type.",

  "calc_parsing": {
    "description": "C++ files involved in parsing CSS calc() expressions",
    "files": [
      {
        "path": "layout/style/ServoCSSParser.cpp",
        "role": "C++ entry-point for CSS parsing",
        "detail": "ServoCSSParser::ParseProperty() delegates all CSS property parsing—including calc()—to the Servo engine via Servo_ParseProperty(). No calc-specific C++ parsing logic exists here; the function is a thin FFI shim that hands the raw CSS string to Rust.",
        "key_functions": ["ServoCSSParser::ParseProperty"]
      },
      {
        "path": "layout/style/ServoStyleConstsInlines.h",
        "role": "C++ inline resolution of the Servo-generated calc AST",
        "detail": "Provides template implementations of LengthPercentage::Resolve() and StyleCalcLengthPercentage::Resolve(). When a LengthPercentage value is a calc() node (IsCalc() == true), Resolve() calls AsCalc().Resolve(basis, rounder), which walks the Rust-generated GenericCalcNode tree and evaluates it to an nscoord. Also declares the template specialisation StyleCalcNode::ScaleLengthsBy<>().",
        "key_functions": [
          "StyleCalcLengthPercentage::Resolve",
          "LengthPercentage::Resolve",
          "LengthPercentage::ResolveToCSSPixels",
          "LengthPercentage::ResolveToCSSPixelsWith",
          "LengthPercentage::ScaleLengthsBy"
        ],
        "relevant_lines": "730-800"
      },
      {
        "path": "layout/style/nsStyleStruct.cpp",
        "role": "C++ template specialisation that traverses the calc() AST",
        "detail": "Implements template<> void StyleCalcNode::ScaleLengthsBy(float aScale). This function walks every node type of the calc AST (Leaf, Clamp, Round, ModRem, MinMax, Sum, Product) and scales all embedded Length leaves by aScale. It is the only C++ function that directly manipulates the internal structure of a calc() expression tree.",
        "key_functions": ["StyleCalcNode::ScaleLengthsBy"],
        "relevant_lines": "3626-3700"
      }
    ],
    "primary_rust_files": [
      {
        "path": "servo/components/style/values/specified/calc.rs",
        "role": "Main calc() parser (Rust)",
        "detail": "Defines MathFunction enum (Calc, Min, Max, Clamp, Round, Mod, Rem, Sin, Cos, Tan, Asin, Acos, Atan, Atan2, Pow, Sqrt, Hypot, Log, Exp, Abs, Sign) and Leaf enum. CalcNode::parse() is the top-level entry point; CalcNode::parse_one() handles individual tokens. CalcLengthPercentage struct carries a clamping_mode: AllowedNumericType field that records the overflow policy chosen at parse time."
      },
      {
        "path": "servo/components/style/values/generics/calc.rs",
        "role": "Generic calc AST and evaluation (Rust)",
        "detail": "Defines GenericCalcNode<L> (Leaf, Negate, Invert, Sum, Product, MinMax, Clamp, Round, ModRem, Hypot, Abs, Sign, Anchor, AnchorSize), CalcNodeLeaf trait, CalcUnits bitflags, RoundingStrategy, MinMaxOp, ModRemOp. The CalcNodeLeaf trait exposes is_infinite(), is_nan(), is_zero() helpers used during simplification."
      },
      {
        "path": "servo/components/style/values/computed/length_percentage.rs",
        "role": "Computed calc() value and Rust-side overflow clamping",
        "detail": "CalcLengthPercentage::resolve() evaluates the calc node tree and then calls self.clamping_mode.clamp(px.px()) to enforce the AllowedNumericType constraint (All or NonNegative) before returning the final Length."
      }
    ]
  },

  "overflow_handling": {
    "description": "C++ files that handle numeric overflow during calc() value resolution",
    "files": [
      {
        "path": "gfx/src/nsCoord.h",
        "role": "Core saturating-arithmetic library for CSS layout coordinates",
        "detail": "Defines nscoord_MAX = (1<<30)-1 and nscoord_MIN = -nscoord_MAX. Provides the complete set of overflow-safe arithmetic used whenever a resolved calc() value is converted to the 30-bit fixed-width nscoord type. These functions are called throughout the layout engine whenever a LengthPercentage (which may be a calc() expression) is resolved to a pixel count.",
        "key_functions": [
          {
            "name": "NSToCoordRoundWithClamp(float/double)",
            "lines": "108-128",
            "description": "Bounds-checks a float before rounding to nscoord; returns nscoord_MAX or nscoord_MIN on overflow. Used as the default rounding callback in LengthPercentage::Resolve()."
          },
          {
